search:react+redux-saga:react redux saga.content:
- **CLI Commands**:
  - `npx create-react-app my-app`
  - `npm install redux react-redux @reduxjs/toolkit redux-saga`

- **Latest Versions**:
  - React: 18.x
  - Redux Toolkit: 2.x
  - Redux-Saga: 1.4.x

- **Key Config Options**:
  - In `store.js`:
    ```javascript
    import { configureStore } from '@reduxjs/toolkit';
    import createSagaMiddleware from 'redux-saga';
    import rootReducer from './reducers';
    import mySaga from './sagas';

    const sagaMiddleware = createSagaMiddleware();

    export default configureStore({
      reducer: rootReducer,
      middleware: [sagaMiddleware],
    });

    sagaMiddleware.run(mySaga);
    ```
  - In `sagas.js`:
    ```javascript
    import { call, put } from 'redux-saga/effects';
    import { fetchTodosSuccess, fetchTodosFailure } from './actions';

    function* fetchTodos() {
      try {
        const response = yield call(fetch, 'https://api.example.com/todos');
        const data = yield response.json();
        yield put(fetchTodosSuccess(data));
      } catch (error) {
        yield put(fetchTodosFailure(error.message));
      }
    }

    export default function* rootSaga() {
      yield takeEvery('FETCH_TODOS', fetchTodos);
    }
    ```
